using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");

            // EF9: discriminator property renamed from "Discriminator" to "$type".
            // Keep old name so existing documents and raw SQL (c.Discriminator) still work.
            b.HasDiscriminator<string>("Discriminator");

            // EF9: id no longer includes the discriminator value.
            // Keep "Product|{key}" format so existing documents are reachable.
            b.HasDiscriminatorInJsonId();

            // EF9: key property is mapped directly to JSON id.
            // Keep EF8 shadow-property approach so the int Id remains a separate JSON field.
            b.HasShadowId();
        });

        // HasIndex removed â€” EF9 Cosmos provider now throws (Cosmos indexes all properties by default).
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

